<script>
import { mdbBtn } from "mdbvue";
import {mapActions, mapGetters} from 'vuex'

export default {
  components: {
    mdbBtn
  },
  data(){
    return{
      start_date: '',
      end_date: '',
      total: {
        "totalQty": 0,
        "totalKg": 0,
        "loadedQty": 0,
        "loadedKg": 0,
        "loadingQty": 0,
        "loadingKg": 0,
        "remainingQty": 0,
        "remainingKg": 0
      },
      order_load_list: [],
      order_category_list: [],
      order_list: [],
      selectedCategoryId: null, // kategoriya bo'yicha filter (id bilan)
      isPdfGenerating: false
    }
  },
  props: {
    // client_info:
    // {
    //   type: Object,
    //   default(){
    //     return {
    //       fio: '',
    //       id:null,
    //     }
    //   }
    // },
    choosen_day: {
      type: String,
      default: ''
    },
  },
  // async mounted(){
  //   await this.fetch_order_all_naqd();
  //   await this.fetch_order_all_summa_online();
  // },
   computed: {
    ...mapGetters(['allcategory']),
    filtered_order_load_list() {
      if (!this.selectedCategoryId) {
        return this.order_load_list;
      }
      return this.order_load_list.filter(it => {
        return it.product && it.product.bot_id === this.selectedCategoryId;
      });
    }
  },
  methods:{
    ...mapActions(['fetchcategory', ]),
    onClickAll() {
      // Hammasi bosilganda filter o'chiriladi
      this.selectedCategoryId = null;
    },
    onClickCategory(cat) {
      // category id ni product.bot_id bilan solishtiramiz
      this.selectedCategoryId = cat.id;
    },
    async func_mounted(){
      // Date inputlarni choosen_day ga tenglashtirish
      if(this.choosen_day){
        this.start_date = this.choosen_day;
        this.end_date = this.choosen_day;
      }
      
      this.clw_cw()
      await this.fetch_get_order_items_summary();
      await this.fetch_get_order_items_summary_total();
      await this.fetchcategory();
      console.log(this.allcategory);
      this.order_category_list = this.allcategory.rows;
      for(let i=0; i<this.order_category_list.length; i++){
        let qty = 0;
        let qty_kg = 0;
        for(let j=0; j< this.order_load_list.length; j++){
          if(this.order_category_list[i].id == this.order_load_list[j].product.bot_id){
            qty += this.order_load_list[j].loadedQty;
            qty_kg += (this.order_load_list[j].loadedQty * this.order_load_list[j].product.real_qty);
          }
        }
        this.order_category_list[i].auth_user_creator_id = qty;
        this.order_category_list[i].auth_user_updator_id = qty_kg;
      }
      console.log(this.order_category_list)
      await this.fetchOrderListByDateRange();

    },
    async onDateChange(){
      await this.fetch_get_order_items_summary();
      await this.fetch_get_order_items_summary_total();
      // Category listni ham yangilash
      for(let i=0; i<this.order_category_list.length; i++){
        let qty = 0;
        let qty_kg = 0;
        for(let j=0; j< this.order_load_list.length; j++){
          if(this.order_category_list[i].id == this.order_load_list[j].product.bot_id){
            qty += this.order_load_list[j].loadedQty;
            qty_kg += (this.order_load_list[j].loadedQty * this.order_load_list[j].product.real_qty);
          }
        }
        this.order_category_list[i].auth_user_creator_id = qty;
        this.order_category_list[i].auth_user_updator_id = qty_kg;
      }
      await this.fetchOrderListByDateRange();
    },
    
    async fetch_get_order_items_summary(){
      // Agar date inputlar bo'sh bo'lsa, choosen_day dan foydalanamiz
      let startDate = this.start_date || this.choosen_day;
      let endDate = this.end_date || this.choosen_day;
      
      let b_data = startDate + 'T00:00:00.000Z';
      let e_data = endDate + 'T00:00:00.000Z';
      this.order_load_list = []

      try{
        const res = await fetch(this.$store.state.hostname + '/TegirmonOrder/order-items-summary?begin_date=' +  b_data + '&end_date=' + e_data);
        const res_data = await res.json();
        console.log('res_data order check hammasi online uchun data')
        console.log(res_data)
          if(res.status == 200 || res.status == 201){
            this.order_load_list = res_data;
          }
      }
      catch{
        console.log('2')
        this.$refs.alert.error("Serverda uzilish bor. Qayta urinib ko'ring !");
        return false;
      }

    },
    formatDate(dateStr){
      if (!dateStr) return '';
      return `${dateStr.slice(8,10)}-${dateStr.slice(5,7)}-${dateStr.slice(0,4)}`;
    },
    formatNumber(value){
      if (value === null || value === undefined) return '';
      const num = Number(value);
      if (Number.isNaN(num)) return '';
      return num.toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ');
    },
    getPayStatus(order){
      if (!order) return '';
      if (order.isPaid) return 'Оплачено';
      if (order.pay_progress > 0) return `${order.pay_progress} %`;
      return 'Не оплачено';
    },
    getLoadStatus(order){
      if (!order) return '';
      if (order.isLoaded && !order.is_loading) return 'Загружен';
      if (order.load_progress > 0) return `${order.load_progress} %`;
      return 'Не загружен';
    },
    getItemCount(order){
      if (!order || !order.item_list) return 0;
      return order.item_list.length;
    },
    toDateKey(dateObj){
      const yyyy = dateObj.getFullYear();
      const mm = String(dateObj.getMonth() + 1).padStart(2, '0');
      const dd = String(dateObj.getDate()).padStart(2, '0');
      return `${yyyy}-${mm}-${dd}`;
    },
    async fetchOrderListByDateRange(){
      let startDate = this.start_date || this.choosen_day;
      let endDate = this.end_date || this.choosen_day;
      if (!startDate || !endDate) {
        this.order_list = [];
        return;
      }
      const start = new Date(`${startDate}T00:00:00`);
      const end = new Date(`${endDate}T00:00:00`);
      const orders = [];
      for (let current = new Date(start); current <= end; current.setDate(current.getDate() + 1)) {
        const dateStr = this.toDateKey(current);
        try{
          const response = await fetch(this.$store.state.hostname + "/TegirmonOrder/getByDate?date=" + dateStr + "&clientId=0");
          const data = await response.json();
          if(response.status == 201 || response.status == 200){
            if (Array.isArray(data)) {
              orders.push(...data);
            }
          }
        }
        catch(error){
          console.log(error);
        }
      }
      const unique = new Map();
      orders.forEach(order => {
        if (order && order.id != null) {
          unique.set(order.id, order);
        }
      });
      this.order_list = Array.from(unique.values());
    },
    async fetch_get_order_items_summary_total(){
      // Agar date inputlar bo'sh bo'lsa, choosen_day dan foydalanamiz
      let startDate = this.start_date || this.choosen_day;
      let endDate = this.end_date || this.choosen_day;
      
      let b_data = startDate + 'T00:00:00.000Z';
      let e_data = endDate + 'T00:00:00.000Z';

      try{
        const res = await fetch(this.$store.state.hostname + '/TegirmonOrder/order-items-summary-total?begin_date=' +  b_data + '&end_date=' + e_data);
        const res_data = await res.json();
        console.log('res_data order check hammasi online uchun data')
        console.log(res_data)
          if(res.status == 200 || res.status == 201){
            this.total = res_data;
          }
      }
      catch{
        console.log('2')
        this.$refs.alert.error("Serverda uzilish bor. Qayta urinib ko'ring !");
        return false;
      }

    },

    clw_cw(){
      this.total = 
        {
        "totalQty": 0,
        "totalKg": 0,
        "loadedQty": 0,
        "loadedKg": 0,
        "loadingQty": 0,
        "loadingKg": 0,
        "remainingQty": 0,
        "remainingKg": 0
      };
    },
    ensureHtml2Pdf() {
      return new Promise((resolve, reject) => {
        if (window.html2pdf) {
          resolve(window.html2pdf);
          return;
        }

        const existing = document.getElementById("html2pdf-script");
        if (existing) {
          existing.addEventListener("load", () => resolve(window.html2pdf));
          existing.addEventListener("error", () => reject(new Error("html2pdf load failed")));
          return;
        }

        const script = document.createElement("script");
        script.id = "html2pdf-script";
        script.src = "https://cdn.jsdelivr.net/npm/html2pdf.js@0.10.1/dist/html2pdf.bundle.min.js";
        script.onload = () => resolve(window.html2pdf);
        script.onerror = () => reject(new Error("html2pdf load failed"));
        document.body.appendChild(script);
      });
    },
    printDiv() {
      let divContents = document.getElementById("load_info_print").innerHTML;

      let styles = "";
      document.querySelectorAll('link[rel="stylesheet"], style').forEach((node) => {
        styles += node.outerHTML;
      });

      let printWindow = window.open("", "", "height=800,width=1000");

      let html =
        '<html>' +
        '<head>' +
        '<title>🚚 Статистика погрузки заказов</title>' +
        styles +
        '<style>' +
        '@page { size: A4; margin: 5mm; }' +
        '@media print { ' +
        'body { zoom: 0.7; -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; color-adjust: exact !important; }' +
        '.no-print { display: none !important; }' +
        '.check_list { min-height: 100% !important; max-height: 100% !important; overflow: visible !important; }' +
        '}' +
        '</style>' +
        '</head>' +
        '<body>' +
        divContents +
        '<script>window.onafterprint = function() { window.close(); }<\/script>' +
        '</body>' +
        '</html>';
      printWindow.document.open();
      printWindow.document.write(html);
      printWindow.document.close();
      printWindow.focus();
      setTimeout(() => {
        printWindow.print();
      }, 1000);
    },
    async savePdf() {
      const source = document.getElementById("load_info_print");
      if (!source) return;

      const tempContainer = document.createElement("div");
      tempContainer.style.position = "fixed";
      tempContainer.style.left = "-10000px";
      tempContainer.style.top = "0";
      tempContainer.style.background = "#fff";
      const a4WidthPx = 1080; // A4 landscape at 96dpi
      tempContainer.style.width = `${a4WidthPx}px`;

      const clone = source.cloneNode(true);
      clone.querySelectorAll(".no-print").forEach((node) => node.remove());
      clone.querySelectorAll(".check_list").forEach((node) => {
        node.style.minHeight = "auto";
        node.style.maxHeight = "none";
        node.style.overflow = "visible";
      });
      clone.querySelectorAll(".pdf-only").forEach((node) => {
        node.style.display = "block";
      });
      const style = document.createElement("style");
      style.textContent = `
        tr, td, th { break-inside: avoid; page-break-inside: avoid; }
        table { page-break-inside: auto; }
      `;
      clone.appendChild(style);
      clone.style.width = `${a4WidthPx}px`;

      tempContainer.appendChild(clone);
      document.body.appendChild(tempContainer);

      try {
        this.isPdfGenerating = true;
        await this.$nextTick();
        await new Promise(resolve => setTimeout(resolve, 300));
        const now = new Date();
        const pad = (value) => String(value).padStart(2, "0");
        const timestamp = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())} ${pad(now.getHours())}-${pad(now.getMinutes())}-${pad(now.getSeconds())}`;
        const html2pdf = await this.ensureHtml2Pdf();
        await html2pdf()
          .from(clone)
          .set({
